// TestFFTMatchesCPU verifies GPU FFT output matches gnark-crypto CPU FFT.
func TestFFTMatchesCPU(t *testing.T) {
	dev := requireGPUDev(t)
	const logN = 14
	n := 1 << logN

	dom := newDomain(t, dev, n)
	cpuDom := fft.NewDomain(uint64(n))

	orig := randFrVec(n)
	cpuCopy := make(fr.Vector, n)
	copy(cpuCopy, orig)

	// CPU FFT
	cpuDom.FFT(cpuCopy, fft.DIF)
	fft.BitReverse(cpuCopy)

	// GPU FFT (DIF: natural → bit-reversed, then BitReverse → natural)
	gV := newGPUVec(t, dev, orig)
	dom.FFT(gV)        // natural → bit-reversed
	dom.BitReverse(gV) // bit-reversed → natural
	dev.Sync()

	gpuResult := make(fr.Vector, n)
	gV.CopyToHost(gpuResult)

	for i := range cpuCopy {
		require.True(t, cpuCopy[i].Equal(&gpuResult[i]),
			"FFT mismatch at i=%d", i)
	}
}

